sql:
SELECT website_link
FROM websites
WHERE type = (SELECT type_id FROM website_types WHERE type_name = 'No-Follow');

SELECT MAX(organic_traffic) AS max_organic_traffic
FROM website_metrics
WHERE date = '2023-02-01';

external_knowledge:
- "Latest backlink" refers to the most recent backlink added to the `backlinks` table for each website;
- "Latest metric update" refers to the most recent update of metrics in the `website_metrics` table for each website;
- "Latest access" refers to the most recent access log entry in the `access_logs` table for each website.

sql:
SELECT COUNT(*) AS website_count
FROM websites
WHERE dr >= 85 AND type = 0;
